module RefModule(
    A,
    B,
    Z
);input [3:0] A;
    input [3:0] B;
    output reg [3:0] Z;  // Change output type from wire to reg

    wire [4:0] obf_temp_sum;

    assign obf_temp_sum = A + B;

    always @(*) begin
        if (obf_temp_sum > 15) begin
            Z = 4'b1111;
        end else begin
            Z = obf_temp_sum[3:0];
        end
    end

endmodule
